var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"가라!! 에잇!","JPN":"行け！！　えいっ！","ENG":"Take that!! Hyah!","TWN":"走開！去去！"},"stage":{"bg":"HIGHWAY_TWILIGHT","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"으아앙! 잘못했어요! 이제 안 때릴게!","JPN":"ふええん！　ごめんなさい！　もう叩かないから！","ENG":"Waah! I'm sorry! I won't hit you again!","TWN":"嗚嗚嗚！對不起！我不該打你的！"},"stage":{"bg":"HIGHWAY_TWILIGHT","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"노엘 양, 교량으로 진입했나?","JPN":"ノエル君、橋まで来たかね？","ENG":"Noelle, are you at the bridge?","TWN":"洛艾兒小姐，你上橋了嗎？"},"stage":{"bg":"HIGHWAY_TWILIGHT","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네에에엣! 거의 다 왔어요! 이제 어떻게 하면 돼요?","JPN":"はいいいいっ！　もうすぐです！　これからどうすればいいんですか？","ENG":"Almost there! What do I have to do next?","TWN":"是！！！我快到了！那接下來該怎麼辦呢？"},"stage":{"bg":"HIGHWAY_TWILIGHT","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 일대는 오랫동안 침식재난 구역으로 지정되어서 시설 관리도 소홀했다네.","JPN":"そこら一帯は長らく侵食災害区域として指定されていたから、施設の管理もなおざりにされている。","ENG":"That area has been designated as a Corruption disaster zone for a long time, so it has not been well maintained.","TWN":"那個地方長期被認定是侵蝕災難地區，因此疏於管理。"},"stage":{"bg":"HIGHWAY_TWILIGHT","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네가 다루는 무기라면 교각을 파괴해서 다리를 무너뜨릴 수 있을 거야.","JPN":"君の武器なら、橋脚を破壊して橋を崩せるはずだ。","ENG":"You should be able to destroy the bridge joints and collapse the bridge with your weapon.","TWN":"你的武器應該可以破壞橋墩讓橋崩塌。"},"stage":{"bg":"HIGHWAY_TWILIGHT","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그런 일이 가능할까요? 전 오늘 침식체랑도 처음 싸워 보는데요?!","JPN":"私にできるんでしょうか？　侵食体とも戦うのも今日が初めてなんですけど！？","ENG":"Do you think that's really possible? I mean, it's my first time fighting a C.O. today!","TWN":"我做得到嗎？我今天才第一次嘗試對付侵蝕體欸？！"},"stage":{"bg":"HIGHWAY_TWILIGHT","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"실패하면 함께 있던 부상자들의 안전은 장담할 수 없을 걸세.","JPN":"失敗すれば一緒にいた怪我人たちの安全は保証できない。","ENG":"If you fail, I cannot guarantee the safety of the people you were with.","TWN":"萬一失敗的話，那就無法保證那些傷者的安全無虞。"},"stage":{"bg":"HIGHWAY_TWILIGHT","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"납치범이나 할 것 같은 협박을! 저 조금 식겁했어요!","JPN":"誘拐犯が言いそうな脅し文句！　私、ちょっとぞっとしました！","ENG":"Whoa, you just sounded like a kidnapper threatening his victim! I got chills running down my spine!","TWN":"怎麼這麼像綁架犯威脅人時說的話！我有點嚇到欸！"},"stage":{"bg":"HIGHWAY_TWILIGHT","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"하지만 무슨 뜻인지는 알겠어요!","JPN":"でも、どういうことなのかはわかります！","ENG":"But yes, I get what you mean!","TWN":"不過我明白老闆的意思了！"},"stage":{"bg":"HIGHWAY_TWILIGHT","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"도전! 지금부터 다리를 무너뜨려 보겠습니다!","JPN":"挑戦！　今から橋を崩してみます！","ENG":"Challenge accepted! I'll try to bring down that bridge!","TWN":"挑戰！我現在就把橋弄塌！"},"stage":{"bg":"HIGHWAY_TWILIGHT","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"부탁해, 바즈라!","JPN":"お願い、ヴァジュラ！","ENG":"I'm counting on you, Vajra!","TWN":"拜託囉，金剛杵！"},"stage":{"bg":"HIGHWAY_TWILIGHT","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"흐이익?!","JPN":"ふええっ！？","ENG":"Eeeek!!","TWN":"欸欸？！"},"stage":{"bg":"HIGHWAY_TWILIGHT","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_EX","text":{"KOREA":"이리 와!! 이 역겨운 계집애야아아아아!","JPN":"こっち来い！！　このムカつく小娘ええええ！","ENG":"Come here!! You filthy little girl!!!","TWN":"給我過來！！你這個臭丫頭！！！"},"stage":{"bg":"HIGHWAY_TWILIGHT","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"사장님! 다리가 안 무너져요!","JPN":"社長！　橋が崩れません！","ENG":"Boss! The bridge won't collapse!","TWN":"老闆！橋沒有塌欸！"},"stage":{"bg":"HIGHWAY_TWILIGHT","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"한두 개로는 부족할 걸세. 침식체가 덮치기 전에 서두르게.","JPN":"一つ二つでは足りないだろう。侵食体が襲ってくる前に急ぐんだ。","ENG":"You will need to destroy more than a couple. Hurry, before the C.O. gets to you.","TWN":"看來破壞一、二個橋墩是不夠的。動作快，侵蝕體就快撲上來了！"},"stage":{"bg":"HIGHWAY_TWILIGHT","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};